// Named aliases over the generated OpenAPI wire contract for the high-risk
// domains. Modules import these instead of hand-declaring backend payload
// shapes, so a backend schema change surfaces as a type error here rather
// than a silent drift. schema.d.ts and openapi.json are generated by
// scripts/generate-api-types.mjs and must never be edited by hand; this file
// is the hand-maintained naming layer over them.

import type { components } from "./schema";

type Schemas = components["schemas"];

// Authentication, users, organizations
export type WireAuthTokenResponse = Schemas["AuthTokenResponse"];
export type WireCurrentUser = Schemas["CurrentUserResponse"];
export type WireOrganization = Schemas["OrganizationResponse"];
export type WireProjectAccess = Schemas["ProjectAccessResponse"];

// Projects and documents
export type WireUserProjectSummary = Schemas["UserProjectSummary"];
export type WireDocumentRead = Schemas["DocumentRead"];
export type WireDocumentPage = Schemas["DocumentPageResponse"];
export type WireDocumentStorageStatus = Schemas["DocumentStorageStatus"];

// Findings and reviewer queue
export type WireFindingRead = Schemas["FindingRead"];
export type WireFindingSource = Schemas["FindingSourceRead"];
export type WireDashboardMetrics = Schemas["DashboardMetrics"];
export type WireDashboardProjectSummary = Schemas["DashboardProjectSummary"];
export type WireReviewerDashboard = Schemas["ReviewerDashboardResponse"];
export type WireReviewerQueue = Schemas["ReviewerQueueResponse"];

// Command center
export type WireCommandCenter = Schemas["ProjectCommandCenterPayload"];
export type WireProjectHealthSummary = Schemas["ProjectHealthSummary"];

// Review packets and response packages
export type WireReviewPacketSummary = Schemas["ReviewPacketSummary"];
export type WireResponsePackageRead = Schemas["ResponsePackageRead"];
export type WireResponsePackageDetail = Schemas["ResponsePackageDetailResponse"];

// CAD intake and file storage
export type WireCadFileUpload = Schemas["CadFileUploadRead"];
export type WireCadParseRun = Schemas["CadParseRunRead"];
export type WireCadMetadata = Schemas["CadMetadataRead"];
export type WireCadUploadLimits = Schemas["CadUploadLimits"];
export type WireStorageHealth = Schemas["StorageHealthResponse"];
